@layer mergora.components {
  .mrg-activity-feed {
    display: grid;
    gap: var(--mrg-semantic-space-stack-sm);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font-family: var(--mrg-semantic-font-family-prose);
  }
  .mrg-activity-feed__list {
    display: grid;
    gap: 0;
    margin: 0;
    padding: 0;
    list-style: none;
  }
  .mrg-activity-feed__event {
    display: grid;
    grid-template-columns: var(--mrg-semantic-size-icon-sm) minmax(0, 1fr);
    gap: var(--mrg-semantic-space-inline-md);
    padding-block: var(--mrg-semantic-space-inset-md);
    border-block-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
  }
  .mrg-activity-feed__mark {
    inline-size: var(--mrg-semantic-size-icon-sm);
    block-size: var(--mrg-semantic-size-icon-sm);
    margin-block-start: var(--mrg-semantic-space-inset-xs);
    border: var(--mrg-semantic-border-width-emphasis) solid var(--mrg-semantic-color-brand-action);
    border-radius: var(--mrg-semantic-radius-compact);
    background: var(--mrg-semantic-color-background-canvas);
  }
  .mrg-activity-feed__action {
    overflow-wrap: anywhere;
    line-height: var(--mrg-semantic-font-line-height-body);
  }
  .mrg-activity-feed time {
    color: var(--mrg-semantic-color-foreground-muted);
    font-size: var(--mrg-semantic-font-size-label);
  }
  .mrg-activity-feed__context {
    margin-block-start: var(--mrg-semantic-space-stack-xs);
    color: var(--mrg-semantic-color-foreground-muted);
    font-size: var(--mrg-semantic-font-size-label);
  }
  .mrg-activity-feed__loading,
  .mrg-activity-feed__error,
  .mrg-activity-feed__summary {
    padding: var(--mrg-semantic-space-inset-sm) var(--mrg-semantic-space-inset-md);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-compact);
    font-size: var(--mrg-semantic-font-size-label);
  }
  .mrg-activity-feed__loading {
    color: var(--mrg-semantic-color-status-loading-foreground);
    background: var(--mrg-semantic-color-status-loading-background);
  }
  .mrg-activity-feed__error {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-inline-sm);
    border-color: var(--mrg-semantic-color-status-danger-border);
    color: var(--mrg-semantic-color-status-danger-foreground);
    background: var(--mrg-semantic-color-status-danger-background);
  }
  .mrg-activity-feed__summary {
    border-color: var(--mrg-semantic-color-status-info-border);
    color: var(--mrg-semantic-color-status-info-foreground);
    background: var(--mrg-semantic-color-status-info-background);
    font-weight: var(--mrg-semantic-font-weight-label);
  }
  .mrg-activity-feed__more,
  .mrg-activity-feed__error button {
    min-block-size: var(--mrg-semantic-size-target-minimum);
    padding-inline: var(--mrg-semantic-density-control-padding-inline);
    border: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-interactive);
    border-radius: var(--mrg-semantic-radius-control);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font: inherit;
  }
  .mrg-activity-feed :is(button):focus-visible {
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: var(--mrg-semantic-focus-offset);
  }
  .mrg-activity-feed__empty {
    padding-block: var(--mrg-semantic-space-stack-lg);
    color: var(--mrg-semantic-color-foreground-muted);
    text-align: center;
  }
  @media (pointer: coarse) {
    .mrg-activity-feed__more,
    .mrg-activity-feed__error button {
      min-inline-size: var(--mrg-semantic-size-target-preferred);
      min-block-size: var(--mrg-semantic-size-target-preferred);
    }
  }
  @media (forced-colors: active) {
    .mrg-activity-feed {
      color: CanvasText;
      background: Canvas;
    }
    .mrg-activity-feed__event {
      border-color: CanvasText;
    }
    .mrg-activity-feed__mark,
    .mrg-activity-feed__loading,
    .mrg-activity-feed__error,
    .mrg-activity-feed__summary,
    .mrg-activity-feed__more,
    .mrg-activity-feed__error button {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
    }
    .mrg-activity-feed :is(button):focus-visible {
      box-shadow: none;
      outline-color: Highlight;
    }
  }
}

import "./activity-feed.css";

import { forwardRef, type HTMLAttributes, type ReactNode } from "react";

export interface ActivityFeedEvent {
  /** Provides the stable event identity used for ordered rendering. */
  readonly id: string;
  /** Presents the event actor without imposing a domain-specific data model. */
  readonly actor: ReactNode;
  /** Presents the action associated with the actor. */
  readonly action: ReactNode;
  /** Supplies a valid timestamp for native time semantics and locale formatting. */
  readonly timestamp: Date | string;
  /** Adds optional event detail without changing the ordered event semantics. */
  readonly context?: ReactNode;
}
export interface ActivityFeedProps extends Omit<HTMLAttributes<HTMLOListElement>, "children"> {
  /** Supplies ordered activity events with stable identities and valid timestamps. */
  readonly events: readonly ActivityFeedEvent[];
  /** Names the native ordered list for assistive technologies. */
  readonly label: string;
  /** Overrides the runtime locale used for event timestamps. */
  readonly locale?: string;
  /** Marks the region busy and shows loading content without mutating events. */
  readonly loading?: boolean;
  /** Replaces the default visible loading status. */
  readonly loadingContent?: ReactNode;
  /** Shows the load-more action when true and no loading or error state is active. */
  readonly hasMore?: boolean;
  /** Enables consumer-owned pagination; omission leaves the load-more action disabled. */
  readonly onLoadMore?: () => void;
  /** Shows consumer-provided recovery content in an alert and suppresses pagination. */
  readonly loadError?: ReactNode;
  /** Enables the retry action only while loadError is present. */
  readonly onRetry?: () => void;
  /** Replaces the default content shown for an empty settled feed. */
  readonly emptyContent?: ReactNode;
  /** Shows loaded-count and continuation status; false removes its live output. */
  readonly showContinuationStatus?: boolean;
}

function classes(...values: readonly (string | undefined | false)[]): string {
  return values.filter((value): value is string => Boolean(value)).join(" ");
}
function toDate(value: Date | string): Date {
  const result = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(result.valueOf()))
    throw new RangeError("Mergora ActivityFeed timestamps must be valid dates.");
  return result;
}

export const ActivityFeed = forwardRef<HTMLOListElement, ActivityFeedProps>(function ActivityFeed(
  {
    events,
    label,
    locale,
    loading = false,
    loadingContent = "Loading activity",
    hasMore = false,
    onLoadMore,
    loadError,
    onRetry,
    emptyContent = "No activity yet",
    showContinuationStatus = false,
    className,
    ...props
  },
  ref,
) {
  const formatter = new Intl.DateTimeFormat(locale, { dateStyle: "medium", timeStyle: "short" });
  return (
    <div className="mrg-activity-feed" data-slot="activity-feed" aria-busy={loading || undefined}>
      <ol
        {...props}
        ref={ref}
        aria-label={label}
        className={classes("mrg-activity-feed__list", className)}
      >
        {events.length === 0 && !loading && !loadError ? (
          <li className="mrg-activity-feed__empty">{emptyContent}</li>
        ) : (
          events.map((event) => {
            const date = toDate(event.timestamp);
            return (
              <li key={event.id} className="mrg-activity-feed__event">
                <span aria-hidden="true" className="mrg-activity-feed__mark" />
                <div>
                  <div className="mrg-activity-feed__action">
                    <strong>{event.actor}</strong> {event.action}
                  </div>
                  <time dateTime={date.toISOString()}>{formatter.format(date)}</time>
                  {event.context ? (
                    <div className="mrg-activity-feed__context">{event.context}</div>
                  ) : null}
                </div>
              </li>
            );
          })
        )}
      </ol>
      {loading ? (
        <div role="status" className="mrg-activity-feed__loading">
          {loadingContent}
        </div>
      ) : null}
      {loadError ? (
        <div role="alert" className="mrg-activity-feed__error">
          <span>{loadError}</span>
          {onRetry ? (
            <button type="button" onClick={onRetry}>
              Retry
            </button>
          ) : null}
        </div>
      ) : null}
      {hasMore && !loading && !loadError ? (
        <button
          type="button"
          className="mrg-activity-feed__more"
          onClick={onLoadMore}
          disabled={onLoadMore === undefined}
        >
          Load more activity
        </button>
      ) : null}
      {showContinuationStatus ? (
        <output
          aria-live="polite"
          className="mrg-activity-feed__summary"
          data-slot="activity-feed-continuation-status"
        >
          {events.length} events loaded ·{" "}
          {loadError
            ? "loading interrupted"
            : loading
              ? "loading more"
              : hasMore
                ? "more available"
                : "end of activity"}
        </output>
      ) : null}
    </div>
  );
});
